const manifest = JSON.parse(items[0].binary.data.toString('utf8'));
const escalationCount = manifest.escalation_queue || 0;
const shutdownEvents  = manifest.shutdown_events  || 0;
const driftAlerts     = manifest.drift_alerts      || [];
const autoRate        = manifest.auto_approve_rate || 0;

return [{
  json: {
    escalationCount,
    shutdownEvents,
    driftAlerts,
    autoRate,
    hasEscalations: escalationCount > 0,
    hasShutdown:    shutdownEvents  > 0,
    hasDrift:       driftAlerts.length > 0,
    batchId:        manifest.batch_id,
    routedAt:       manifest.routed_at,
  }
}];

const data = items[0].json;
return [{
  json: {
    subject:  '[P0 CRITICAL] HITL-Ops — SHUTDOWN EVENT DETECTED',
    message:  `🔴 SHUTDOWN ALERT

Batch: ${data.batchId}
Shutdown Events: ${data.shutdownEvents}
Escalations: ${data.escalationCount}
Auto-approve rate: ${(data.autoRate*100).toFixed(1)}%

Immediate action required.
Review interface: http://localhost:8765

Time: ${data.routedAt}`,
    priority: 'P0',
    alert_type: 'shutdown',
  }
}];

const data = items[0].json;
return [{
  json: {
    subject:  '[P1 ALERT] HITL-Ops — Escalation Queue Non-Empty',
    message:  `🟠 ESCALATION ALERT

Batch: ${data.batchId}
Escalations: ${data.escalationCount}
Auto-approve rate: ${(data.autoRate*100).toFixed(1)}%
Drift alerts: ${data.driftAlerts.join('; ') || 'None'}

Review interface: http://localhost:8765

Time: ${data.routedAt}`,
    priority: 'P1',
    alert_type: 'escalation',
  }
}];

const data = items[0].json;
return [{
  json: {
    subject:  '[INFO] HITL-Ops — Pipeline Complete, No Escalations',
    message:  `✅ PIPELINE COMPLETE\n\nBatch: ${data.batchId}\nAll records auto-approved.\nAuto-approve rate: ${(data.autoRate*100).toFixed(1)}%\n\nDashboard: http://localhost:8501\n\nTime: ${data.routedAt}`,
    priority: 'P4',
    alert_type: 'info',
  }
}];

// Log alert to console (replace with email/Slack in production)
const alert = items[0].json;
console.log(`[HITL-Ops Alert] ${alert.subject}`);
console.log(alert.message);

// Write alert to log file
const fs      = require('fs');
const path    = require('path');
const logDir  = '/Users/prateekgaur/Desktop/github/hitl-ops/results';
const logFile = path.join(logDir, 'n8n_alerts.jsonl');

const entry = JSON.stringify({
  ...alert,
  logged_at: new Date().toISOString(),
}) + '\n';

fs.appendFileSync(logFile, entry);

return items;

// Pipeline completion summary
const timestamp = new Date().toISOString();
console.log(`[HITL-Ops] Pipeline run complete at ${timestamp}`);

return [{
  json: {
    pipeline_complete: true,
    completed_at: timestamp,
    components_run: [
      'extraction_agent',
      'anomaly_agent',
      'classification_agent',
      'decision_agent',
      'confidence_router',
      'feedback_loop',
    ],
    dashboard_url: 'http://localhost:8501',
    review_url:    'http://localhost:8765',
    gate_url:      'http://localhost:8766',
  }
}];
